import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub

# Set up service account with broad permissions
os.environ["GOOGLE_APPLICATION_CREDENTIALS"] = "path/to/service/account/key.json"

# Create Cloud Storage client
storage_client = storage.Client()

# Create Firestore client
firestore_client = firestore.Client()

# Create Pub/Sub client
pubsub_client = pubsub.PublisherClient()

# Define function to process files from Cloud Storage and write to Firestore
def process_files(event, context):
    # Get list of files in Cloud Storage bucket
    bucket_name = "your-bucket-name"
    blobs = storage_client.list_blobs(bucket_name)
    
    # Loop through each file and write to Firestore
    for blob in blobs:
        # Get file contents as string
        file_contents = blob.download_as_string()
        
        # Write file contents to Firestore
        firestore_client.collection("your-collection").document(blob.name).set({"file": file_contents})
        
        # Publish message to Pub/Sub topic
        pubsub_client.publish(topic="your-topic", data=file_contents)